              <span className="text-[10px] font-mono text-[var(--color-fg-dim)]">
                {initialsFrom(it.name)}
              </span>
            )}
          </div>
        ))}
        {bundle.items.length > 6 && (
          <span className="text-[11px] font-mono text-[var(--color-fg-dim)]">
            +{bundle.items.length - 6}
          </span>
