/**
 * Connectors content loader.
 *
 * Two sources merge into the public `/connectors` catalog:
 *   1. First-party — Markdown files at `content/connectors/<lang>/<slug>.md`
 *      with YAML frontmatter. Curated by the TS team. Edit the .md files
 *      to update copy without a code change.
 *   2. Marketplace — third-party `connector_listings` rows in Supabase
 *      with status='approved'. Lives behind `listMarketplaceConnectors()`.
 *
 * Use `listAllConnectors(lang)` to get both sources merged for the index.
 */

import fs from "node:fs";
import path from "node:path";
import matter from "gray-matter";
import { remark } from "remark";
import html from "remark-html";
import { getSupabaseAdmin } from "./supabaseAdmin";
import { manifestRequiresEnvSecrets } from "./marketplace/secrets";

export interface ConnectorMeta {
  slug: string;
  name: string;
  logo: string; // path relative to /public, or absolute https URL for marketplace
  category:
    | "productivity"
    | "database"
    | "automation"
    | "storage"
/**
 * Skills content loader.
 *
 * Mirrors the connectors loader (src/lib/connectors.ts) but for "skills" —
 * markdown prompt-recipes that get installed into ~/.claude/skills/<name>/
 * by the desktop client. A skill is conceptually different from a connector:
 *   - Connector  = MCP server config (Claude gets tools for an external API).
 *   - Skill      = SKILL.md prompt instructions (Claude gets behavior).
 *
 * Each skill lives at content/skills/<lang>/<slug>.md with YAML frontmatter
 * including `vendors: ["claude", "codex"]` so the same skill can target
 * multiple AI vendors.
 */

import fs from "node:fs";
import path from "node:path";
import matter from "gray-matter";
import { remark } from "remark";
import html from "remark-html";

