"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";

interface Props {
  lang: string;
}

export function CatalogNav({ lang }: Props) {
  const pathname = usePathname();

  return (
    <nav className="cat-tabs-wrap" aria-label="Categorías del catálogo">
      <div className="wrap">
        <div className="cat-tabs">
          <Link
            href={`/${lang}/stacks`}
            className={`cat-tab${pathname.includes("/stacks") ? " on" : ""}`}
          >
            {lang === "es" ? "Kits" : "Kits"} <span className="n">17</span>
          </Link>
          <Link
            href={`/${lang}/connectors`}
            className={`cat-tab${pathname.includes("/connectors") ? " on" : ""}`}
          >
            {lang === "es" ? "Conectores" : "Connectors"}{" "}
            <span className="n">13</span>
          </Link>
          <Link
            href={`/${lang}/skills`}
            className={`cat-tab${pathname.includes("/skills") ? " on" : ""}`}
          >
            {lang === "es" ? "Asistentes" : "Skills"}{" "}
            <span className="n">8</span>
          </Link>
          <Link
            href={`/${lang}/cli-tools`}
            className={`cat-tab${pathname.includes("/cli-tools") ? " on" : ""}`}
          >
            {lang === "es" ? "Herramientas CLI" : "CLI Tools"}{" "}
            <span className="n">5</span>
          </Link>
        </div>
      </div>
    </nav>
  );
}

