/* ── Design system v2 aliases (shorter names used by new components) ─── */
:root {
  --bg: var(--color-bg);
  --bg-2: #fffefb;
  --surface: var(--color-panel);
  --surface-2: var(--color-panel-2);
  --line: var(--color-border);
  --line-2: var(--color-border-strong);
  --fg: var(--color-fg);
  --fg-2: var(--color-fg-muted);
  --fg-3: var(--color-fg-dim);
  --accent: var(--color-accent);
  --accent-2: var(--color-accent-soft);
  --accent-ink: #ffffff;
  --accent-soft: color-mix(in oklab, var(--color-accent) 12%, transparent);
  --accent-line: color-mix(in oklab, var(--color-accent) 32%, transparent);
  --glow: rgba(15,157,110,0.14);
  --claude: var(--color-claude);
  --codex: #2dd4a7;
  --gemini: #5b9cff;
  --sans: var(--font-sans);
  --mono: var(--font-mono);
  --r-sm: 8px;
  --r: 14px;
  --r-lg: 22px;
  --maxw: 1140px;
  --gut: clamp(20px, 5vw, 40px);
  --ease: cubic-bezier(.22,.61,.36,1);
}

:root[data-theme="dark"] {
  --bg-2: #0c0e12;
  --surface: #111419;
  --surface-2: #161a20;
  --accent-ink: #04130d;
  --glow: transparent;
}

/* ── Layout utilities (used by new catalog + landing components) ──────── */
.wrap {
  max-width: var(--maxw);
  margin: 0 auto;
  padding-inline: var(--gut);
}

.section {
  padding-block: clamp(64px, 9vw, 120px);
  position: relative;
}

.section--tight {
  padding-block: clamp(44px, 6vw, 72px);
}

.section-head {
  margin-bottom: clamp(36px, 5vw, 56px);
}

.h-section {
  font-size: clamp(28px, 4.2vw, 46px);
  letter-spacing: -0.035em;
  line-height: 1.12;
  margin-top: 18px;
  max-width: 18ch;
  padding-bottom: 0.08em;
  font-weight: 600;
}

.sub-section {
  color: var(--fg-2);
  font-size: clamp(16px, 1.6vw, 19px);
  margin-top: 16px;
  max-width: 56ch;
}

.center .h-section,
.center .sub-section {
  margin-inline: auto;
}

/* ── Eyebrow label ────────────────────────────────────────────────────── */
.eyebrow {
  font-family: var(--mono);
  font-size: 12.5px;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: var(--accent);
  font-weight: 500;
  display: inline-flex;
  align-items: center;
  gap: 8px;
}

.eyebrow::before {
  content: "";
  width: 6px;
  height: 6px;
  border-radius: 2px;
  background: var(--accent);
  box-shadow: 0 0 10px var(--accent);
  flex-shrink: 0;
}

/* ── Buttons ──────────────────────────────────────────────────────────── */
.btn {
  display: inline-flex;
  align-items: center;
  gap: 9px;
  padding: 13px 22px;
  border-radius: 999px;
  font-weight: 500;
  font-size: 15.5px;
  letter-spacing: -0.01em;
  transition: transform .18s var(--ease), background .2s, border-color .2s, box-shadow .25s;
  white-space: nowrap;
  cursor: pointer;
  text-decoration: none;
  font-family: var(--sans);
  border: none;
  line-height: 1;
}

.btn:active { transform: scale(.97); }

.btn-primary {
  background: var(--accent);
  color: var(--accent-ink);
  font-weight: 600;
