  return {
    title,
    description,
    openGraph: { title, description, type: "website" },
  };
}

const CATEGORY_LABELS_ES: Record<string, string> = {
  productivity: "Productividad",
  database: "Base de datos",
  automation: "Automatización",
  storage: "Almacenamiento",
  messaging: "Mensajería",
  dev: "Desarrollo",
};
const CATEGORY_LABELS_EN: Record<string, string> = {
  productivity: "Productivity",
  database: "Database",
  automation: "Automation",
  storage: "Storage",
  messaging: "Messaging",
  dev: "Developer",
};

export default async function ConnectorsIndex({ params }: Props) {
  const { lang } = await params;
  const connectors = await listAllConnectors(lang);
  const categoryLabels = lang === "es" ? CATEGORY_LABELS_ES : CATEGORY_LABELS_EN;
  const isEs = lang === "es";

  return (
    <main className="min-h-screen bg-[var(--color-bg)] text-[var(--color-fg)]">
      <div className="cat-head">
        <div className="wrap">
          <span className="eyebrow">
            {isEs ? "Conectores" : "Connectors"}
          </span>
          <h1>
            {isEs
              ? "Conecta tus herramientas favoritas"
              : "Connect your favorite tools"}
          </h1>
          <p className="lead">
            {isEs
              ? "Gmail, Notion, Airtable, GitHub y muchos más — arrastra el conector a tu sesión y tu IA lo usa al instante. Cifrado de extremo a extremo."
              : "Gmail, Notion, Airtable, GitHub and many more — drag the connector to your session and your AI uses it instantly. End-to-end encrypted."}
          </p>
        </div>
      </div>

      <CatalogNav lang={lang} />

      <ConnectorsExplorer
        lang={lang}
        connectors={connectors}
        categoryLabels={categoryLabels}
        uiText={{
          all: isEs ? "Todos" : "All",
          searchPlaceholder: isEs ? "Buscar por nombre o tag…" : "Search by name or tag…",
          noResults: isEs ? "Sin resultados." : "No results.",
          soon: isEs ? "Pronto" : "Soon",
        }}
      />

      <div className="wrap">
        <div className="cat-hint">
          <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
            <path d="M12 5v14M5 12l7 7 7-7"/>
          </svg>
          {isEs
            ? "Arrastra cualquier ítem a tu sesión de TerminalSync para instalarlo · Cero código"
            : "Drag any item to your TerminalSync session to install it · Zero code"}
        </div>

        <Link
          href={`/${lang}/publishers`}
          className="group flex items-center justify-between gap-4 rounded-2xl border border-[var(--color-accent)]/25 bg-[var(--color-accent)]/5 hover:bg-[var(--color-accent)]/10 p-5 transition-colors mb-24"
        >
          <div>
            <p className="text-[13.5px] font-semibold tracking-tight text-[var(--color-fg-strong)]">
              {isEs
                ? "¿Construís conectores MCP? Publicalos acá."
                : "Building MCP connectors? Publish them here."}
            </p>
            <p className="mt-1 text-[12.5px] text-[var(--color-fg-muted)]">
              {isEs
                ? "Cobrás el 90%. Los primeros 50 publishers no pagan comisión durante 6 meses."
                : "You keep 90%. First 50 publishers pay 0% for 6 months."}
            </p>
          </div>
          <ArrowUpRight
            size={18}
            className="text-[var(--color-accent)] shrink-0 group-hover:translate-x-0.5 group-hover:-translate-y-0.5 transition-transform"
          />
        </Link>
      </div>
    </main>
  );
}

